import{_ as o,o as t,c as a,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Adding Notes","description":"","frontmatter":{},"headers":[],"relativePath":"coach-notes/adding-notes.md","filePath":"coach-notes/adding-notes.md"}'),n={name:"coach-notes/adding-notes.md"};function i(r,e,d,l,h,c){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="adding-notes" tabindex="-1">Adding Notes <a class="header-anchor" href="#adding-notes" aria-label="Permalink to &quot;Adding Notes&quot;">​</a></h1><h2 id="quick-note-from-dashboard" tabindex="-1">Quick Note from Dashboard <a class="header-anchor" href="#quick-note-from-dashboard" aria-label="Permalink to &quot;Quick Note from Dashboard&quot;">​</a></h2><p>The fastest way to capture a thought is the <strong>Quick Note</strong> button on the dashboard. Tap it, type or speak, and save. The note is timestamped and stored in your notes history.</p><h2 id="notes-on-player-profiles" tabindex="-1">Notes on Player Profiles <a class="header-anchor" href="#notes-on-player-profiles" aria-label="Permalink to &quot;Notes on Player Profiles&quot;">​</a></h2><p>For player-specific observations open the player&#39;s profile and tap the <strong>Notes</strong> tab. Notes added here are automatically tagged to that player — you do not need to manually identify who the note is about.</p><h2 id="notes-hub" tabindex="-1">Notes Hub <a class="header-anchor" href="#notes-hub" aria-label="Permalink to &quot;Notes Hub&quot;">​</a></h2><p>The Notes hub (accessible via the More menu) shows all notes across all players and session types. Use it to:</p><ul><li>Browse recent notes</li><li>Search note history by player, date, or keyword</li><li>Access <strong>Process Notes with AI</strong></li></ul><h2 id="note-content-tips" tabindex="-1">Note Content Tips <a class="header-anchor" href="#note-content-tips" aria-label="Permalink to &quot;Note Content Tips&quot;">​</a></h2><p>Effective notes are specific and observable:</p><p><strong>Good:</strong> &quot;Glaros arm path is dragging behind his body on fastballs — elbow dropping below shoulder during acceleration&quot;</p><p><strong>Less useful:</strong> &quot;Glaros needs to work on his mechanics&quot;</p><p>Specific observations translate directly into useful AI processing results and better training plan notes.</p><h2 id="linking-notes-to-sessions" tabindex="-1">Linking Notes to Sessions <a class="header-anchor" href="#linking-notes-to-sessions" aria-label="Permalink to &quot;Linking Notes to Sessions&quot;">​</a></h2><p>When adding a note you can optionally link it to a specific game or practice session. Linked notes appear in the session detail view and are referenced when the AI processes notes with session context.</p>',15)])])}const b=o(n,[["render",i]]);export{u as __pageData,b as default};
